('gt-011','xitong','系统流','{"type":"system_growth","power_system":"任务-奖励-商城-成就","levels":"新手任务-主线任务-隐藏任务-权限升级-系统真相","world_origin":"现实/异界中嵌入可量化规则"}','{"total_volumes":6,"rhythm":"任务驱动","volume_goals":["绑定系统","完成新手期","解锁核心功能","系统反噬","揭开来源","超越系统"]}','{"protagonist":"目标明确+善用规则","system":"既是外挂也是约束","rival":"同类宿主/规则破坏者","ally":"被主角能力改变的人"}','{"hook_type":"任务发布/奖励未知","climax_type":"规则极限反杀","tension_source":"任务惩罚+时间限制+系统隐瞒"}','{"rules":["系统规则必须前后一致","奖励不能无成本解决所有问题","任务失败要有代价"]}',2200,5000,'现代利落+规则提示','["陆行","顾衡","许知远","沈砚"]'),
('gt-012','wuxian','无限流','{"type":"instance_worlds","power_system":"副本规则+道具+团队博弈","levels":"新人副本-进阶副本-团队副本-阵营战-主神真相","world_origin":"主神空间/规则空间"}','{"total_volumes":7,"rhythm":"副本循环","volume_goals":["入局","求生","组队","破局","阵营对抗","规则反叛","终局真相"]}','{"protagonist":"冷静观察+高压决策","teammate":"能力互补但立场不稳","rival":"资深玩家","enemy":"副本规则与人心"}','{"hook_type":"副本规则公布","climax_type":"规则漏洞破局","tension_source":"死亡倒计时+信息差+队友背叛"}','{"rules":["每个副本必须有清晰规则","破局依赖线索而非作者强行解释","死亡威胁要真实"]}',2500,5200,'冷静紧张+规则感','["陈序","林烬","许南星","周既白"]'),
('gt-013','moshi','末世','{"type":"apocalypse","power_system":"资源+武器+异能/感染","levels":"幸存者-小队-据点-区域势力-文明重建","world_origin":"灾变、病毒、天灾或异种入侵"}','{"total_volumes":6,"rhythm":"生存扩张","volume_goals":["逃生","建队","夺资源","建基地","区域争霸","文明选择"]}','{"protagonist":"务实果断+底线摇摆","ally":"技术/医疗/战斗成员","rival":"资源竞争者","enemy":"灾变体与秩序崩塌"}','{"hook_type":"资源告急/尸潮逼近","climax_type":"据点攻防","tension_source":"饥饿+背叛+感染风险"}','{"rules":["资源消耗必须可追踪","安全区不能绝对安全","牺牲与收益要匹配"]}',2200,4800,'冷硬写实+短句','["秦野","姜霁","陆沉舟","闻夏"]'),
('gt-014','saibo','赛博朋克','{"type":"cyberpunk","power_system":"义体改造+黑客网络+资本权限","levels":"街区佣兵-公司棋子-网络幽灵-城市变量-系统颠覆者","world_origin":"高科技低生活的巨型城市"}','{"total_volumes":5,"rhythm":"黑色任务","volume_goals":["接单","卷入阴谋","挑战公司","网络觉醒","城市改写"]}','{"protagonist":"边缘佣兵/黑客","mentor":"旧时代技术人","rival":"公司特工","ally":"地下医生/情报贩"}','{"hook_type":"委托反转/记忆异常","climax_type":"潜入与追杀","tension_source":"公司监控+身份剥夺+身体代价"}','{"rules":["技术能力要有成本","公司逻辑必须冷酷自洽","不要把赛博只写成霓虹装饰"]}',2300,4800,'冷峻短句+黑色幽默','["乔临","岑光","洛迦","安弥"]'),
