('gt-016','guize','规则怪谈','{"type":"rule_horror","power_system":"规则文本+污染值+认知博弈","levels":"读规则-试探规则-利用规则-篡改规则-逃离规则源头","world_origin":"异常空间或被污染的日常场景"}','{"total_volumes":5,"rhythm":"规则解谜","volume_goals":["入场","验证规则","找到矛盾","利用漏洞","直面规则源头"]}','{"protagonist":"谨慎观察+反常识推理","ally":"不完全可信的同伴","rival":"误导者","enemy":"规则本身/伪装者"}','{"hook_type":"新规则出现/旧规则失效","climax_type":"用规则反制规则","tension_source":"认知污染+信息真假+一步错即死"}','{"rules":["规则必须可被读者复盘","恐怖来自限制而非堆怪","谜底不能违背已公布规则"]}',1800,3800,'冷感克制+短段落','["许默","林昼","周白","沈听"]'),
