('gt-018','xingzhen','刑侦','{"type":"criminal_investigation","power_system":"侦查流程+法医技术+协同办案","levels":"接警-勘验-走访-并案-抓捕-庭审余波","world_origin":"现实城市案件网络"}','{"total_volumes":5,"rhythm":"案件单元+主线黑幕","volume_goals":["单案立住","团队磨合","并案升级","黑幕浮现","收网"]}','{"protagonist":"刑警/法医/画像师","ally":"专案组成员","rival":"上级压力/媒体舆论","enemy":"连环犯或利益链"}','{"hook_type":"尸检发现/监控盲区","climax_type":"抓捕行动","tension_source":"证据链压力+嫌疑人逃逸+舆论时间窗"}','{"rules":["办案流程要可信","证据链不能靠直觉替代","案件尺度要尊重现实逻辑"]}',2200,4500,'硬核克制+流程感','["江砚","沈知夏","顾明川","程澈"]'),
