('gt-021','shangzhan','职场商战','{"type":"business","power_system":"资源、人脉、信息、谈判与组织能力","levels":"基层-骨干-负责人-合伙人-行业玩家","world_origin":"现代行业竞争"}','{"total_volumes":5,"rhythm":"项目推进","volume_goals":["入局","立项","危机","反击","定局"]}','{"protagonist":"专业能力强+情绪克制","mentor":"行业前辈","rival":"竞争公司/内部派系","ally":"团队成员/客户"}','{"hook_type":"合同变故/竞品截胡","climax_type":"谈判翻盘/发布会","tension_source":"现金流+舆论+组织内耗"}','{"rules":["商业决策要有利益逻辑","不能用空泛口号解决经营问题","职场权责要清晰"]}',2000,4200,'现代利落+信息密度','["秦策","周聿","林嘉树","温宁"]'),
