INSERT OR IGNORE INTO style_profiles (id, name, metrics, preferred_patterns, anti_ai_features, sample_paragraphs, banned_patterns, is_builtin, created_at, updated_at) VALUES
('style-09','系统爽文','{"dialogue_ratio":35,"description_density":"low","pace":"very_fast","chapter_highlights":"每章至少一次任务/奖励/权限变化"}','{"sentence_length":"short","paragraph_length":"short-medium","transitions":"任务触发→选择→反馈","focus":"规则提示与即时爽点"}','{"avoid":["解释系统来源过早","奖励万能化","重复任务播报"]}','["【新任务已触发。】陆行看了一眼倒计时，没急着动。系统给了三条路，他选了最危险、也最值钱的一条。"]','{"banned":["系统无所不能","奖励直接解决所有冲突","宿主毫无代价"]}',1,datetime('now'),datetime('now')),
('style-10','无限副本冷压','{"dialogue_ratio":28,"description_density":"medium","pace":"tense","chapter_highlights":"规则公布、试错、破局"}','{"sentence_length":"short-medium","paragraph_length":"short","transitions":"线索递进","focus":"倒计时、规则矛盾、团队压力"}','{"avoid":["怪物堆砌","规则不可复盘","队友无意义牺牲"]}','["广播第三次响起时，走廊尽头多了一扇门。林烬没有过去。他先数了一遍门牌，发现少了四号。"]','{"banned":["突然出现的万能线索","毫无代价的复活","规则前后矛盾"]}',1,datetime('now'),datetime('now')),
('style-11','规则怪谈冷感','{"dialogue_ratio":20,"description_density":"medium","pace":"slow_tension","chapter_highlights":"每章验证一条关键规则"}','{"sentence_length":"short","paragraph_length":"short","transitions":"观察→试探→异常反馈","focus":"日常物的陌生化"}','{"avoid":["过度尖叫","直接解释恐怖来源","密集形容词"]}','["冰箱上的纸条换了位置。许默记得很清楚，昨晚它贴在左上角，现在却压住了门缝。"]','{"banned":["恐怖如斯","令人毛骨悚然地尖叫","无法形容的恐惧反复出现"]}',1,datetime('now'),datetime('now')),
('style-12','刑侦硬核','{"dialogue_ratio":35,"description_density":"medium","pace":"procedural","chapter_highlights":"证据推进而非灵感推进"}','{"sentence_length":"short-medium","paragraph_length":"medium","transitions":"勘验→走访→研判","focus":"证据链与流程可信"}','{"avoid":["神探一眼看穿","流程跳步","煽情覆盖证据"]}','["江砚把物证袋放到灯下。塑封边缘有一道压痕，不像运输造成，更像有人重新封过。"]','{"banned":["我有一种预感","凶手一定是他但没有证据","法医一分钟出完整结论"]}',1,datetime('now'),datetime('now')),
('style-13','赛博冷峻','{"dialogue_ratio":32,"description_density":"medium","pace":"fast","chapter_highlights":"任务反转与身体代价"}','{"sentence_length":"short","paragraph_length":"short-medium","transitions":"镜头切换","focus":"义体、霓虹、公司压迫"}','{"avoid":["空泛霓虹装饰","技术无成本","世界观解释堆叠"]}','["雨水沿着义眼外壳往下淌。乔临眨了眨眼，广告牌在视网膜里碎成一片红色噪点。"]','{"banned":["未来科技十分发达","炫酷无比的义体","没有代价的黑入"]}',1,datetime('now'),datetime('now')),
('style-14','轻小说吐槽','{"dialogue_ratio":55,"description_density":"low","pace":"bright","chapter_highlights":"角色反差和关系推进"}','{"sentence_length":"short-medium","paragraph_length":"short","transitions":"对话驱动","focus":"吐槽、反差、轻快节奏"}','{"avoid":["吐槽过密打断剧情","人设只有萌点","长篇设定说明"]}','["我本来只是想把作业交了。真的。直到学生会长把一把剑塞进我书包，说这是今天的社团活动。"]','{"banned":["为了吐槽而吐槽","角色只会卖萌","无目标日常"]}',1,datetime('now'),datetime('now')),
('style-15','群像史诗','{"dialogue_ratio":30,"description_density":"high","pace":"layered","chapter_highlights":"多线推进与时代压迫"}','{"sentence_length":"medium-long","paragraph_length":"medium-long","transitions":"场景并置","focus":"人物选择汇成时代变化"}','{"avoid":["频繁无标识切视角","口号化宏大","人物功能化"]}','["城门关闭的时候，北线的雪还没有停。有人在殿上争一纸军令，有人在城下等一碗热粥。"]','{"banned":["所有人都为主角服务","宏大但无具体细节","视角混乱"]}',1,datetime('now'),datetime('now')),
('style-16','商战利落','{"dialogue_ratio":45,"description_density":"low","pace":"fast","chapter_highlights":"信息差、谈判、反制"}','{"sentence_length":"short","paragraph_length":"short-medium","transitions":"会议→动作→结果","focus":"利益逻辑和决策压力"}','{"avoid":["空泛霸总话术","商业问题靠气场解决","无成本融资"]}','["周聿把报价单推回去，只说了两个字：重算。会议室安静下来，对方终于意识到，他们漏掉的不是成本，是渠道。"]','{"banned":["天凉王破","一句话收购公司","不讲现金流"]}',1,datetime('now'),datetime('now')),
('style-17','校园青春清爽','{"dialogue_ratio":45,"description_density":"low","pace":"gentle","chapter_highlights":"小事件推动关系变化"}','{"sentence_length":"short-medium","paragraph_length":"short","transitions":"生活细节衔接","focus":"克制情绪、青春遗憾、成长"}','{"avoid":["强行狗血","成年人式权谋","过度华丽辞藻"]}','["夏栀把试卷折起来，塞进书包最里面。窗外蝉声很响，她却只听见身后那个人轻轻敲了两下桌面。"]','{"banned":["全校都震惊了","青春疼痛堆砌","无来由误会"]}',1,datetime('now'),datetime('now')),
('style-18','现实主义克制','{"dialogue_ratio":38,"description_density":"medium","pace":"steady","chapter_highlights":"具体生活压力与选择"}','{"sentence_length":"medium","paragraph_length":"medium","transitions":"因果推进","focus":"职业、家庭、金钱、情感的真实摩擦"}','{"avoid":["口号化苦难","强行圆满","过度煽情"]}','["她在楼下站了十分钟，还是没有上去。手机里那条催缴短信亮着，像一盏不肯熄的灯。"]','{"banned":["生活虽然苦但一定会好","所有矛盾靠一句理解解决","苦难堆叠"]}',1,datetime('now'),datetime('now'));

INSERT OR IGNORE INTO writing_patterns (id, source_type, source_ref, pattern_name, genre_compat, description, usage_guide, sample_text, created_at) VALUES
('wp-001','builtin','craft','开章异常钩子','通用','开篇第一屏给出一个不该出现的异常，迫使读者追问原因。','用于章节开头；异常要和本章主线相关，不能只做气氛。','门是从里面锁上的，可屋里多了一双湿鞋。',datetime('now')),
('wp-002','builtin','craft','任务倒计时','系统流,无限流,规则怪谈','用明确时限压缩选择空间，让行动更紧迫。','倒计时必须影响决策，并在章末兑现或升级。','倒计时还剩十分钟，第三条规则却被人撕掉了。',datetime('now')),
('wp-003','builtin','craft','以弱胜强三段式','玄幻,仙侠,武侠,系统流','先展示差距，再布置限制，最后用代价和策略反杀。','避免纯爆种；反杀依据要提前出现。','他赢的不是力量，是对方只剩一次出手的耐心。',datetime('now')),
('wp-004','builtin','craft','打脸回环','都市,系统流,玄幻,商战','前段建立轻视，中段压低预期，后段用事实反打。','打脸对象要有具体利益或立场，避免空喊嘲讽。','刚才笑得最大声的人，现在第一个低头看合同。',datetime('now')),
('wp-005','builtin','craft','伏笔三拍','通用','埋设、提醒、回收三次出现，形成读者可复盘的闭环。','每次出现信息量递增，不要机械重复。','那枚裂开的扣子，第三次出现时，已经在凶手袖口上。',datetime('now')),
('wp-006','builtin','craft','情绪递进阶梯','言情,校园青春,现实主义,通用','用小动作、误解、选择逐级推高情绪。','每一级都要有外部事件推动，少用直接心理说明。','她没有哭，只把那张票撕得很慢。',datetime('now')),
('wp-007','builtin','craft','副本规则验证','无限流,规则怪谈','角色主动测试规则，得到部分确认和新的风险。','规则验证要有代价，不能像教程说明。','他没有进电梯，只把硬币滚了进去。电梯门合上后，硬币开始尖叫。',datetime('now')),
('wp-008','builtin','craft','线索误导反转','悬疑推理,刑侦','让一个线索先指向错误答案，再通过细节翻转。','误导必须公平，读者回看能发现破绽。','血迹是真的，时间却是假的。',datetime('now')),
('wp-009','builtin','craft','团队功能位','电竞,体育竞技,无限流,军事','让每个队友在关键场景承担不可替代的功能。','避免主角包办全部胜利。','他不需要拿人头，只要把对面的退路封死。',datetime('now')),
('wp-010','builtin','craft','资源账本压力','末世,星际科幻,商战','用可消耗资源制造真实限制。','资源减少要改变计划，不能只做背景。','燃油只够开到下一个镇，前提是他们不绕路救人。',datetime('now')),
('wp-011','builtin','craft','谈判筹码翻转','商战,历史,职场商战','表面弱势方亮出隐藏筹码，改变谈判桌权力。','筹码来源要提前埋线。','他没有加价，只把第二份授权书推了出来。',datetime('now')),
('wp-012','builtin','craft','比赛最后一回合','电竞,体育竞技','把胜负压到最后一个动作，放大准备与心理。','最后动作前要铺垫技术短板或战术选择。','球离网只有半寸，他却在那半寸里改了方向。',datetime('now')),
('wp-013','builtin','craft','冷启动世界观','科幻,赛博朋克,星际科幻','不解释设定，先让角色在设定后果中行动。','用物品、制度和代价呈现世界。','义眼广告在他视野里闪烁，提醒他本月租金已逾期。',datetime('now')),
('wp-014','builtin','craft','不可名状留白','克苏鲁诡秘,灵异,规则怪谈','只展示影响和边缘，不把恐怖实体解释完整。','用反应、痕迹、认知错误写恐惧。','录音里没有声音，只有所有人同时停下呼吸的空白。',datetime('now')),
('wp-015','builtin','craft','权谋双层话术','历史,商战,玄幻','对话表层谈小事，底层完成试探、威胁或结盟。','每句台词都要有未说出口的目的。','他说的是茶凉了，殿里的人听见的是该换人了。',datetime('now')),
('wp-016','builtin','craft','章末选择钩子','通用','结尾不给答案，给两个都要付代价的选择。','选择要承接本章，不要突然抛新坑。','救人就会暴露身份，不救人就再也问不出真相。',datetime('now')),
('wp-017','builtin','craft','能力代价即时化','玄幻,系统流,科幻,赛博朋克','使用能力立刻带来身体、资源或关系代价。','代价要影响下一场行动。','义体过热时，他闻到了自己皮肤烧焦的味道。',datetime('now')),
('wp-018','builtin','craft','关系反差甜点','言情,轻小说,校园青春','用角色口是心非或行为反差制造甜点。','甜点要推动关系变化，不只卖萌。','她说只是顺路，却把伞偏向了他那边。',datetime('now')),
('wp-019','builtin','craft','低谷后小胜','体育竞技,电竞,玄幻,现实主义','大失败后安排一个小但确定的进步，维持希望。','小胜不能解决主矛盾，只证明方向正确。','这次他还是输了，但比分第一次没有被拉开。',datetime('now')),
('wp-020','builtin','craft','群像接力推进','群像史诗,历史,军事,星际科幻','不同地点角色各自推进一小步，最后汇成大事件。','切换要有清晰时间/地点标识。','北线失守的消息传到王都时，南港的船刚刚离岸。',datetime('now')),
('wp-021','builtin','craft','敌人合理胜利','通用','让反派阶段性胜利，证明其能力和威胁。','敌人胜利要靠已知优势，而非主角降智。','他没有猜错，只是对方比他早一天知道答案。',datetime('now')),
('wp-022','builtin','craft','日常物恐怖化','规则怪谈,灵异,克苏鲁诡秘','把普通物件写成规则异常入口。','避免堆形容词，靠位置、数量、功能异常制造不安。','餐桌上多了一副碗筷，筷尖全都朝着她。',datetime('now')),
('wp-023','builtin','craft','技术细节可信化','科幻,刑侦,电竞,体育竞技','用少量准确细节建立专业可信度。','细节服务决策，不写百科。','他没有看尸斑，先看空调温度和门缝灰尘。',datetime('now')),
('wp-024','builtin','craft','误会即时澄清失败','言情,校园青春,轻小说','角色试图解释，但外部事件打断，误会升级。','误会要源于性格或信息差，不能靠不说人话。','她刚说出第一个字，广播里就念到了他的名字。',datetime('now')),
('wp-025','builtin','craft','危机三选一','末世,无限流,军事,商战','同时给出三个坏选择，凸显领导力和代价。','选择后必须失去某些东西。','守仓库会丢人，救人会丢粮，撤退会丢掉整条街。',datetime('now')),
('wp-026','builtin','craft','升级前置门槛','玄幻,系统流,游戏','升级前设置资源、认知或情绪门槛。','升级不只是数值变化，要带来新问题。','他终于能开第二层权限，也终于看见了系统隐藏的红字。',datetime('now')),
('wp-027','builtin','craft','证据链闭环','刑侦,悬疑推理','物证、人证、时间线相互扣合后再定论。','至少两类证据互相支撑。','鞋印证明他来过，通话记录证明他没时间离开。',datetime('now')),
('wp-028','builtin','craft','训练反馈闭环','体育竞技,电竞','训练动作在比赛中兑现，形成爽感。','前文训练细节要在关键局变成胜负手。','他被骂了三周的起跳，终于在最后一球救了全队。',datetime('now')),
('wp-029','builtin','craft','黑色幽默缓压','赛博朋克,末世,轻小说','高压场景里用短促幽默释放一点人味。','幽默不能破坏危机，只让角色更鲜活。','他说保险过期了。她看着追来的无人机，说那你死得很不划算。',datetime('now')),
('wp-030','builtin','craft','主线暗涌单元剧','轻小说,校园青春,刑侦,无限流','每章解决一个小事件，同时露出主线的一角。','单元结尾要留下主线推进证据。','社团委托结束后，照片背面的符号还在发烫。',datetime('now'));
